import 'package:flutter/material.dart';
import 'package:get/get.dart';

void main() async {
  await GetStorage.init();
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return GetMaterialApp(
      home: StorageDemo(),
    );
  }
}

class SettingsController extends GetxController {
  final box = GetStorage();
  var username = ''.obs;

  @override
  void onInit() {
    super.onInit();
    username.value = box.read('username') ?? '';
  }

  void saveUsername(String name) {
    username.value = name;
    box.write('username', name);
  }

  void clearUsername() {
    username.value = '';
    box.remove('username');
  }
}

class StorageDemo extends StatelessWidget {
  final controller = Get.put(SettingsController());
  final TextEditingController textController = TextEditingController();

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('GetStorage Demo')),
      body: Padding(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Obx(() => Text(
              'Stored username: ${controller.username.value.isEmpty ? 'Not set' : controller.username.value}',
              style: TextStyle(fontSize: 20),
            )),
            SizedBox(height: 20),
            TextField(
              controller: textController,
              decoration: InputDecoration(labelText: 'Enter username'),
            ),
            SizedBox(height: 10),
            ElevatedButton(
              onPressed: () {
                if (textController.text.isNotEmpty) {
                  controller.saveUsername(textController.text);
                  textController.clear();
                }
              },
              child: Text('Save'),
            ),
            ElevatedButton(
              onPressed: controller.clearUsername,
              child: Text('Clear'),
            ),
          ],
        ),
      ),
    );
  }
}
